var e=[{id:`L2_1`,type:`dialog`,speaker:`STUDENT_EXTRA_B_TWINTAIL`,text:{KOREA:`정말 이래도 괜찮은 걸까?`,JPN:`本当にこんなことをして大丈夫なのかな？`,ENG:`You sure it'll be okay?`,TWN:`這樣真的沒問題嗎？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`STUDENT_EXTRA_A_TWINTAIL`,text:{KOREA:`이제 와서 뭘 그래?`,JPN:`今更何を言ってんだよ。`,ENG:`We can't back out now!`,TWN:`現在說這些幹嘛？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`STUDENT_EXTRA_B_TWINTAIL`,text:{KOREA:`우리 때문에 그 애가 잘못되기라도 하면…`,JPN:`俺たちのせいであの子の身に何か起きたら……`,ENG:`But if something happens to her because of us...`,TWN:`萬一她因此怎麼樣的話…`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`먼저들 와서 기다리고 있었구려.`,JPN:`お待ちしておりました。`,ENG:`I see you were waiting for me.`,TWN:`你們先來這裡等在下嗎？`},stage:{bg:`PARK_DESTROYED`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`STUDENT_EXTRA_B_TWINTAIL`,text:{KOREA:`어엇… 아, 안녕? 왔구나?`,JPN:`あっ……や、やあ？`,ENG:`O-oh... H-hi. You're here.`,TWN:`呃…喔，哈，哈囉？你來啦？`},stage:{bg:`PARK_DESTROYED`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`STUDENT_EXTRA_A_TWINTAIL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`PARK_DESTROYED`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`STUDENT_EXTRA_A_TWINTAIL`,text:{KOREA:`이제 가자.`,JPN:`よし、行こう。`,ENG:`Let's go, then.`,TWN:`我們走吧。`},stage:{bg:`PARK_DESTROYED`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`STUDENT_EXTRA_A_TWINTAIL`,text:{KOREA:`여기가 공포의 집이야. 아마도 침식체는… 여기서 나타날 거야.`,JPN:`ここが恐怖の家だ。おそらく侵食体が現れるのは……ここだ。`,ENG:`This is the haunted house. I think... the C.O.'s gonna be here.`,TWN:`這裡跟鬼屋一樣…可能會有侵蝕體跑出來。`},stage:{bg:`HALL`,slots:{L:null,C:null,R:null}}},{id:`L15_1`,type:`dialog`,speaker:`STUDENT_EXTRA_B_TWINTAIL`,text:{KOREA:`이, 이쪽엔 아무것도 없는 것 같은데… 좀 더 안쪽으로 들어가볼까?`,JPN:`こ、ここには何もないみたいだぞ……もう少し奥に入ってみよう。`,ENG:`Th-there's nothing over here... Should we go in deeper?`,TWN:`這，這裡好像沒東西…要再往裡面一點嗎？`},stage:{bg:`HALL`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`HALL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`STUDENT_EXTRA_A_TWINTAIL`,text:{KOREA:`으앗! 바닥이…!`,JPN:`うわっ！　床が……！`,ENG:`Whoa! The floor...!`,TWN:`啊！地板…！`},stage:{bg:`HALL`,slots:{L:null,C:null,R:null}}},{id:`L24_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`길이 낡았소. 조심하구려.`,JPN:`かなり足元が脆いです。ご注意を。`,ENG:`The path is dilapidated. Be careful.`,TWN:`地板有點老舊，要小心。`},stage:{bg:`HALL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`STUDENT_EXTRA_A_TWINTAIL`,text:{KOREA:`응… 잡아줘서 고마워.`,JPN:`ああ……支えてくれてありがとうな。`,ENG:`Yeah... Thanks for catching me.`,TWN:`嗯…謝謝你抓住我。`},stage:{bg:`HALL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`STUDENT_EXTRA_B_TWINTAIL`,text:{KOREA:`위험했네. 나무바닥이 다 삭았잖아.`,JPN:`危なかったな。木の床が朽ちているみたいだぞ。`,ENG:`That was close. The wooden floor has rotted all the way.`,TWN:`好危險，木頭地板都腐蝕了。`},stage:{bg:`HALL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`STUDENT_EXTRA_A_TWINTAIL`,text:{KOREA:`그래… 침식파가 거쳐간 건물은 빨리 낡는 경우도 있댔으니까. 내가 부주의했어.`,JPN:`ああ……一度侵食波に襲われた建物は劣化が早くなることもあるって知ってたのに、不注意だった。`,ENG:`Yeah... Places where the Corruption ray passed tend to age quicker. I should've been more careful.`,TWN:`是啊…聽說被侵蝕波侵蝕過的建築物都會腐蝕得比較快，剛剛是我太不小心。`},stage:{bg:`HALL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`지금부터는 본인이 앞장서리다.`,JPN:`ここから先は自分が先頭に立って進むとしましょう。`,ENG:`From this point, I shall take lead.`,TWN:`換在下走前面吧。`},stage:{bg:`HALL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L33_1`,type:`dialog`,speaker:`STUDENT_EXTRA_A_TWINTAIL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`HALL`,slots:{L:null,C:null,R:null}}},{id:`L34_1`,type:`narration`,speaker:null,text:{KOREA:`<color=#ff3636>그 친구. 아카데미에 오기 전엔 사람을 수도 없이 죽여본 살인마거든.</color>`,JPN:`<color=#ff3636>あいつ。アカデミーに来る前は、数えきれないほどの人を殺してきた殺人鬼なんだぞ。</color>`,ENG:`<color=#ff3636>That girl. She is a murderer who has taken countless lives before attending the Academy.</color>`,TWN:`<color=#ff3636>她在來學院之前，是個殺人無數的殺人魔。</color>`},stage:{bg:`HALL`,slots:{L:null,C:null,R:null}}}];export{e as default};